// CollectFields tells the query-builder to eagerly load connected nodes by resolver context.
func (_q *TagQuery) CollectFields(ctx context.Context, satisfies ...string) (*TagQuery, error) {
	fc := graphql.GetFieldContext(ctx)
	if fc == nil {
		return _q, nil
	}
	if err := _q.collectField(ctx, false, graphql.GetOperationContext(ctx), fc.Field, nil, satisfies...); err != nil {
		return nil, err
	}
	return _q, nil
}

func (_q *TagQuery) collectField(ctx context.Context, oneNode bool, opCtx *graphql.OperationContext, collected graphql.CollectedField, path []string, satisfies ...string) error {
	path = append([]string(nil), path...)
	var (
		unknownSeen    bool
		fieldSeen      = make(map[string]struct{}, len(tag.Columns))
		selectedFields = []string{tag.FieldID}
	)
	for _, field := range graphql.CollectFields(opCtx, collected.Selections, satisfies) {
		switch field.Name {

		case "posts":
			var (
				alias = field.Alias
				path  = append(path, alias)
				query = (&PostClient{config: _q.config}).Query()
			)
			if err := query.collectField(ctx, false, opCtx, field, path, mayAddCondition(satisfies, postImplementors)...); err != nil {
				return err
			}
			_q.WithNamedPosts(alias, func(wq *PostQuery) {
				*wq = *query
			})
		case "createdAt":
			if _, ok := fieldSeen[tag.FieldCreatedAt]; !ok {
				selectedFields = append(selectedFields, tag.FieldCreatedAt)
				fieldSeen[tag.FieldCreatedAt] = struct{}{}
			}
		case "updatedAt":
			if _, ok := fieldSeen[tag.FieldUpdatedAt]; !ok {
				selectedFields = append(selectedFields, tag.FieldUpdatedAt)
				fieldSeen[tag.FieldUpdatedAt] = struct{}{}
			}
		case "brief":
			if _, ok := fieldSeen[tag.FieldBrief]; !ok {
				selectedFields = append(selectedFields, tag.FieldBrief)
				fieldSeen[tag.FieldBrief] = struct{}{}
			}
		case "isFeatured":
			if _, ok := fieldSeen[tag.FieldIsFeatured]; !ok {
				selectedFields = append(selectedFields, tag.FieldIsFeatured)
				fieldSeen[tag.FieldIsFeatured] = struct{}{}
			}
		case "name":
			if _, ok := fieldSeen[tag.FieldName]; !ok {
				selectedFields = append(selectedFields, tag.FieldName)
				fieldSeen[tag.FieldName] = struct{}{}
			}
		case "sortOrder":
			if _, ok := fieldSeen[tag.FieldSortOrder]; !ok {
				selectedFields = append(selectedFields, tag.FieldSortOrder)
				fieldSeen[tag.FieldSortOrder] = struct{}{}
			}
		case "id":
		case "__typename":
		default:
			unknownSeen = true
		}
	}
	if !unknownSeen {
		_q.Select(selectedFields...)
	}
	return nil
}

